params.description:
Command-specific parameters. Examples:
  navigate:     {"url": "https://example.com"}
  click:        {"selector": "#submit-btn"}
  type:         {"selector": "input[name='q']", "text": "hello"}
  getText:      {"selector": "h1"}  (omit selector for whole page)
  getAttribute: {"selector": "a.link", "attribute": "href"}
  scroll:       {"x": 0, "y": 500}
  scrollBy:     {"dx": 0, "dy": 300}
  evaluate:     {"code": "document.title"}
  waitForElement: {"selector": ".result", "timeout": 5000}
  findElements: {"selector": "a[href]"}
  fillForm:     {"data": {"#email": "user@example.com", "#pass": "secret"}}
  switchTab:    {"tabId": 123}
  closeTab:     {"tabId": 123}
  newTab:       {"url": "https://example.com"}
